DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "parserAssignment.pl",
  "parserOneOf.pl",
  "contextForm.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
package my::OneOf;
our @ISA = ('parser::OneOf');
sub cmp_compare {
  my ($self,$other,$ans) = @_;
  foreach $answer (@{$self->{data}}) {
    if ($answer->typeMatch($other)) {
      my $result = $answer->cmp->evaluate($other);
      if ($result->{score}) {
        $ans->score($result->{score});
        $ans->{ans_message} = $result->{ans_message};
        return $ans->{score};
      }
      if ($result->{ans_message}) {
        $ans->{ans_message} = $result->{ans_message}
          if !$ans->{ans_message} || length($ans->{ans_message}) > length($result->{ans_message});
      }
    }
  }
  return 0;
}
package main;
sub OneOfForm {my::OneOf->new(@_)}

Context("Form")->variables->add(y=>'Real');
parser::Assignment->Allow;
$ps = OneOfForm(Formula("y=25/12*(x-37)+40"), Formula("y=25/12*(x+11)-60"));
$si = Formula("y=25/12x-445/12");

############################################################
# Body
############################################################

BEGIN_PGML
A line passes through [`(37,40)`] and [`(-11,-60)\text{.}`] Find equations for this line using both point-slope and slope-intercept form.

[@KeyboardInstructions('Enter a point-slope equation here.')@]**

[_]{$ps}{16}

[@KeyboardInstructions('Enter a slope-intercept equation here.')@]**

[_]{$si}{16}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
First, use the slope formula to find the slope of this line:

[```\newcommand{\amp}{&}
\begin{aligned}
m=\frac{y_2-y_1}{x_2-x_1}\amp=\frac{-60-40}{-11-37}\\
\amp=\frac{-100}{-48}\\
\amp=\frac{25}{12}\text{.}
\end{aligned}
```]

The generic point-slope equation is [`y=m(x-x_0)+y_0\text{.}`] We have found the slope, [`m\text{,}`] and we may use [`(37,40)`] for [`(x_0,y_0)\text{.}`] So an equation in point-slope form is [`[$ps]\text{.}`]

To find a slope-intercept form equation, we can take the generic [`y=mx+b`] and substitute in the value of [`m`] we found. Also, we know that [`(x,y)=(-11,-60)`] should make the equation true. So we have

[```\newcommand{\addright}[1]{{\highlight{{{}+#1}}}}\newcommand{\multiplyright}[2][\cdot]{{\highlight{{{}#1#2}}}}\newcommand{\divideunder}[2]{\frac{#1}{{\highlight{{#2}}}}}\newcommand{\amp}{&}
\begin{aligned}
y\amp=mx+b\\
-60\amp=\frac{25}{12}(-11)+b\amp\amp\text{(now we may solve for }b\text{)}\\
-60\multiplyright{12}\amp=\left(\frac{25}{12}(-11)+b\right)\multiplyright{12}\amp\amp\text{(clear the denominator)}\\
-720\amp=25(-11)+12b\amp\amp\text{(distribute and multiply)}\\
-720\amp=-275+12b\\
-720\addright{275}\amp=264+12b\addright{275}\\
-445\amp=12b\\
\divideunder{-445}{12}\amp=\divideunder{12b}{12}\amp\amp b = -\frac{445}{12}\text{.}
\end{aligned}
```]

So the slope-intercept equation is [`[$si]\text{.}`] Note that the slope-intercept equation has an unfriendly fraction, and the fact that this can happen is another reason to use the point-slope form whenever it is reasonable to do so.

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
